class ExchangePostModel {  int? productId;  dynamic? productVariationId;  int? sizeId;  dynamic? optionId;  int? quantity;  int? price;  int? totalPrice;  ExchangePostModel(      {required this.productId,        required this.productVariationId,        required this.sizeId,        required this.optionId,        required  this.quantity,        required  this.price,        required this.totalPrice});  ExchangePostModel.fromJson(Map<String, dynamic> json) {    productId = json['product_id'];    productVariationId = json['product_variation_id'];    sizeId = json['size_id'];    optionId = json['option_id'];    quantity = json['quantity'];    price = json['price'];    totalPrice = json['total_price'];  }  Map<String, dynamic> toJson() {    final Map<String, dynamic> data = new Map<String, dynamic>();    data['product_id'] = this.productId;    data['product_variation_id'] = this.productVariationId;    data['size_id'] = this.sizeId;    data['option_id'] = this.optionId;    data['quantity'] = this.quantity;    data['price'] = this.price;    data['total_price'] = this.totalPrice;    return data;  }}